import React from "react";
import Navbar from 'react-bootstrap/Navbar';
import Nav from 'react-bootstrap/Nav';
import NavDropdown from 'react-bootstrap/NavDropdown';
import { withRouter } from 'react-router-dom';
import "../styles/header.css";
import "../index.css";

const linkToText = {
  "/aboutMe" : "About Me",
  "/reviews" : "Film Reviews", 
  "/portfolio" : "Portfolio", 
  "/contact" : "Contact"
};

class Header extends React.Component {

  getLink = (linkName) => {

    return (
      <Nav.Link
        className="header-content"
        href={linkName}
        key={linkName}
      >
        { linkToText[linkName] }
      </Nav.Link>
    );
  }

  render() {
    return (
      <div >

        <Navbar className="header-outer" expand="md" fixed="top" onSelect="test()">
            <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
            </Navbar.Brand>
            <Navbar.Toggle aria-controls="responsive-navbar-nav"/>
            <Navbar.Collapse className="justify-content-end">
                <Nav className="mr-auto">
                <Nav.Link className="header-content" href="/aboutMe">About Me</Nav.Link>
                <Nav.Link className="header-content" href="/reviews">Film Reviews</Nav.Link>
                <Nav.Link className="header-content" href="/portfolio">Portfolio</Nav.Link>
                <Nav.Link className="header-content" href="/contact">Contact</Nav.Link>
                </Nav>
            </Navbar.Collapse>
        {/* <Navbar.Collapse id="responsive-navbar-nav">
          <Nav>
            <div className="header-inner header-content">{ Object.keys(linkToText).map(this.getLink) }</div>
          </Nav>
          </Navbar.Collapse> */}
      </Navbar>
      </div>
    );
  }
}
export default withRouter(Header);
